(function (window) {
  function chain() {
    var api = {};
    ["append","attr","style","text","datum","data","enter","selectAll","call"].forEach(function (name) {
      api[name] = function () { return api; };
    });
    return api;
  }
  function scale() {
    var fn = function () { return 0; };
    fn.range = function () { return fn; };
    fn.domain = function () { return fn; };
    return fn;
  }
  window.d3 = {
    time: { format: function () { return { parse: function (value) { return new Date(value); } }; }, scale: scale },
    scale: { linear: scale, category10: function () { return function () { return "#2563eb"; }; } },
    svg: { axis: function () { return chain(); }, line: function () { var fn = function () { return ""; }; fn.interpolate = fn.x = fn.y = function () { return fn; }; return fn; } },
    select: function () { return chain(); },
    csv: function (url, callback) {
      var xhr = new XMLHttpRequest();
      xhr.onreadystatechange = function () {
        if (xhr.readyState === 4) {
          if (xhr.status >= 200 && xhr.status < 300) {
            var lines = xhr.responseText.trim().split(/\r?\n/);
            var headers = lines.shift().split(",");
            var data = lines.map(function (line) {
              var values = line.split(",");
              var row = {};
              headers.forEach(function (header, index) { row[header] = values[index]; });
              return row;
            });
            callback(null, data);
          } else {
            callback(new Error("CSV load failed"));
          }
        }
      };
      xhr.open("GET", url, true);
      xhr.send();
    },
    extent: function (items, fn) { var values = items.map(fn); return [values[0], values[values.length - 1]]; },
    min: function (items, fn) { return Math.min.apply(null, items.map(fn)); },
    max: function (items, fn) { return Math.max.apply(null, items.map(fn)); }
  };
})(window);
